private void xrTableCell28_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e)
{
    decimal saleableChicks = 0;
    decimal settedEggs = 0;

    if (GetCurrentColumnValue("SaleableChicks") != null)
        saleableChicks = Convert.ToDecimal(GetCurrentColumnValue("SaleableChicks"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    decimal percentage = 0;
    if (settedEggs != 0)
        percentage = (saleableChicks * 100m) / settedEggs;


    XRTableCell cell = sender as XRTableCell;
    cell.Text = percentage.ToString("0.00");
    saleableChicksReport += saleableChicks ;
    SettedEggssSaleableChicksReport += settedEggs ;

}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e)
{
    decimal saleableChicks = 0;
    decimal settedEggs = 0;

    if (GetCurrentColumnValue("SaleableChicks") != null)
        saleableChicks = Convert.ToDecimal(GetCurrentColumnValue("SaleableChicks"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    decimal percentage = 0;
    if (settedEggs != 0)
        percentage = (saleableChicks * 100m) / settedEggs;

    saleableChicksGroup += saleableChicks ;
    settedEggsGroup += settedEggs ;
    if (settedEggsGroup != 0)
         SaleableChicksPercGroup = (saleableChicksGroup * 100)  /  settedEggsGroup ;


    //
      decimal rejectChicks = 0;

    if (GetCurrentColumnValue("RejectChicks") != null)
        rejectChicks = Convert.ToDecimal(GetCurrentColumnValue("RejectChicks"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    if (settedEggs != 0)
        percentage = (rejectChicks * 100m) / settedEggs;

    rejectChicksGroup += rejectChicks ;
    settedEggsRejGroup += settedEggs ;

    if (settedEggsRejGroup != 0)
         RejectChicksPercGroup = (rejectChicksGroup * 100)  /  settedEggsRejGroup ;

    //
       if (GetCurrentColumnValue("SaleableChicks") != null)
        saleableChicks = Convert.ToDecimal(GetCurrentColumnValue("SaleableChicks"));

    if (GetCurrentColumnValue("RejectChicks") != null)
        rejectChicks = Convert.ToDecimal(GetCurrentColumnValue("RejectChicks"));

    saleableChicksGroup += saleableChicks ;
    rejectChicksGroup += rejectChicks  ;

    groupSumSaleableRejectChicks = saleableChicksGroup  + rejectChicksGroup  ;

    //
    if (settedEggs != 0)
        percentage = ((saleableChicks + rejectChicks) * 100m) / settedEggs;

    TotalPercGroup += percentage;




 }


