private void xrTableCell34_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e)
{
    decimal saleableChicks = 0;
    decimal rejectChicks = 0;
    decimal settedEggs = 0;

    if (GetCurrentColumnValue("SaleableChicks") != null)
        saleableChicks = Convert.ToDecimal(GetCurrentColumnValue("SaleableChicks"));

    if (GetCurrentColumnValue("RejectChicks") != null)
        rejectChicks = Convert.ToDecimal(GetCurrentColumnValue("RejectChicks"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    decimal percentage = 0;
    if (settedEggs != 0)
        percentage = ((saleableChicks + rejectChicks) * 100m) / settedEggs;

    TotalPerc += percentage;

    XRTableCell cell = sender as XRTableCell;
    cell.Text = percentage.ToString("0.00");
}

