private void xrTableCell38_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    string lineType = string.Empty;

if (GetCurrentColumnValue("LineType") != null && 
    !string.IsNullOrEmpty(GetCurrentColumnValue("LineType").ToString()))
{
    lineType = GetCurrentColumnValue("LineType").ToString();
}
else
{
    lineType = " ";
}

XRTableCell cell = sender as XRTableCell;
cell.Text = lineType;

}
